#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    if (std::endian::native != std::endian::big) {
        hexi::endian::be_inplace(value);
    }
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    if (std::endian::native != std::endian::little) {
        hexi::endian::le_inplace(value);
    }
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    if (from != to) {
        if (from == std::endian::big && to == std::endian::little) {
            hexi::endian::b_to_l_inplace(value);
        } else if (from == std::endian::little && to == std::endian::big) {
            hexi::endian::l_to_b_inplace(value);
        } else {
            // Conditional approach for other cases
            if (from != std::endian::native) {
                if constexpr (from == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else if constexpr (from == std::endian::little) {
                    hexi::endian::le_inplace(value);
                }
            }
            if (to != std::endian::native) {
                if constexpr (to == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else if constexpr (to == std::endian::little) {
                    hexi::endian::le_inplace(value);
                }
            }
        }
    }
}
```

**Explanation:**

1. **`convert_from_big_endian_inplace`**: Checks if native endianness is not big endian, then uses `hexi::endian::be_inplace` to convert from big endian to native.

2. **`convert_from_little_endian_inplace`**: Checks if native endianness is not little endian, then uses `hexi::endian::le_inplace` to convert from little endian to native.

3. **`convert_endianness_inplace`**: 
   - First handles the specific big↔little and little↔big cases with dedicated functions
   - For other cases, uses conditional logic:
     - If source endianness (`from`) isn't native, convert it to native first
     - If target endianness (`to`) isn't native, convert from native to target
   - Uses `constexpr if` for compile-time condition checking

The implementation follows the exact specifications provided, using the appropriate `hexi::endian` functions for each conversion scenario while handling endianness detection correctly.

