    // Peek at data without advancing read pointer
    std::vector<uint8_t> peeked_data(peek_size);
    adaptor.copy(peeked_data.data(), peek_size);

    // Get pointer to current read position
    const uint8_t* read_pointer = adaptor.read_ptr();

    // Actually consume the data by reading it
    std::vector<uint8_t> consumed_data(peek_size);
    adaptor.read(consumed_data.data(), peek_size);

    return peeked_data;
}
